/* ═══════════════════════════════════════════════════════════════════════════
   AURA ALPHA — Pipeline Monitor
   Real-time pipeline phase tracking, feature freshness, ML model health,
   and backtest staleness — with one-click pipeline triggers.
   ═══════════════════════════════════════════════════════════════════════════ */
import React, { useState, useEffect, useCallback } from 'react';
import { tokens } from '../styles/tokens';
import { getApiBase } from '../utils/platform';
import s from './PipelineMonitorPage.module.css';

// ── Design tokens shorthand ─────────────────────────────────────────────────
const C = {
  bg: tokens.color.bg, surface: tokens.color.surface, border: tokens.color.border,
  text: tokens.color.text, textSec: tokens.color.textSecondary,
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue, amber: tokens.color.amber,
};
const mono = tokens.font.mono;
const sans = tokens.font.sans;

// ── Pipeline phases ─────────────────────────────────────────────────────────
const PHASES = [
  'OHLCV', 'Signals', 'Backtests', 'Features',
  'ML Train', 'ML Refresh', 'EC2 Sync', 'Done',
];

// ── Freshness color helper ──────────────────────────────────────────────────
function freshnessColor(hours, thresholds = { green: 24, amber: 168 }) {
  if (hours == null) return C.textSec;
  if (hours < thresholds.green) return C.green;
  if (hours < thresholds.amber) return C.amber;
  return C.red;
}

function backtestFreshnessColor(hours) {
  if (hours == null) return C.textSec;
  if (hours < 24) return C.green;
  if (hours < 72) return C.amber;
  return C.red;
}

// ── Format helpers ──────────────────────────────────────────────────────────
function fmtAge(hours) {
  if (hours == null) return '--';
  if (hours < 1) return `${Math.round(hours * 60)}m`;
  if (hours < 24) return `${hours.toFixed(1)}h`;
  return `${(hours / 24).toFixed(1)}d`;
}

function fmtElapsed(seconds) {
  if (seconds == null || seconds < 0) return '--';
  const m = Math.floor(seconds / 60);
  const sec = Math.floor(seconds % 60);
  return m > 0 ? `${m}m ${sec}s` : `${sec}s`;
}

// ── Reusable card wrapper ───────────────────────────────────────────────────
function Card({ title, children, className }) {
  return (
    <div className={className || s.card}>
      {title && <div className={s.cardTitle}>{title}</div>}
      {children}
    </div>
  );
}

// ── Action button ───────────────────────────────────────────────────────────
function ActionButton({ label, onClick, loading, color = C.blue }) {
  return (
    <button
      onClick={onClick}
      disabled={loading}
      className={`${s.actionButton} ${loading ? s.actionButtonDisabled : ''}`}
      style={{
        background: `${color}18`, border: `1px solid ${color}40`,
        color, cursor: loading ? 'not-allowed' : 'pointer',
        opacity: loading ? 0.5 : 1,
      }}
    >
      {loading ? 'Submitting...' : label}
    </button>
  );
}

// ── Phase Stepper ───────────────────────────────────────────────────────────
function PhaseStepper({ currentPhase }) {
  const currentIdx = PHASES.indexOf(currentPhase);

  return (
    <div className={s.stepper}>
      {PHASES.map((phase, i) => {
        let color = C.border;
        let textColor = C.textSec;
        if (i < currentIdx || currentPhase === 'Done') {
          color = C.green;
          textColor = C.green;
        } else if (i === currentIdx && currentPhase !== 'Done') {
          color = C.blue;
          textColor = C.blue;
        }

        return (
          <React.Fragment key={phase}>
            <div className={s.stepColumn}>
              <div
                className={`${s.stepCircle} ${i === currentIdx && currentPhase !== 'Done' ? s.stepCircleActive : ''}`}
                style={{
                  background: i < currentIdx || currentPhase === 'Done' ? color : 'transparent',
                  border: `2px solid ${color}`,
                  color: i < currentIdx || currentPhase === 'Done' ? '#fff' : color,
                  boxShadow: i === currentIdx && currentPhase !== 'Done' ? `0 0 12px ${color}50` : 'none',
                }}
              >
                {i < currentIdx || currentPhase === 'Done' ? '\u2713' : i + 1}
              </div>
              <span className={s.stepLabel} style={{ color: textColor }}>
                {phase}
              </span>
            </div>
            {i < PHASES.length - 1 && (
              <div
                className={s.stepConnector}
                style={{ background: i < currentIdx || currentPhase === 'Done' ? C.green : C.border }}
              />
            )}
          </React.Fragment>
        );
      })}
    </div>
  );
}

// ── Feature Freshness Card ──────────────────────────────────────────────────
function FeatureCard({ label, data }) {
  const ageHours = data?.age_hours;
  const color = freshnessColor(ageHours);

  return (
    <div className={s.featureCard}>
      <div className={s.featureHeader}>
        <span className={s.featureLabel}>{label}</span>
        <span className={s.ageBadge} style={{ color, background: `${color}15`, border: `1px solid ${color}30` }}>
          {ageHours != null ? fmtAge(ageHours) : 'N/A'}
        </span>
      </div>
      <div className={s.featureGrid}>
        {[
          { k: 'Size', v: data?.size_mb != null ? `${data.size_mb} MB` : '--' },
          { k: 'Rows', v: data?.rows?.toLocaleString() ?? '--' },
          { k: 'Symbols', v: data?.symbols ?? '--' },
          { k: 'Updated', v: data?.updated_at ? new Date(data.updated_at).toLocaleDateString() : '--' },
        ].map(({ k, v }) => (
          <div key={k}>
            <div className={s.featureStatLabel}>{k}</div>
            <div className={s.featureStatValue}>{v}</div>
          </div>
        ))}
      </div>
    </div>
  );
}

// ── ML Models Summary Card ──────────────────────────────────────────────────
function MLModelsCard({ models }) {
  const count = models?.count ?? 0;
  const newestAge = models?.newest_age_hours;
  const oldestAge = models?.oldest_age_hours;
  const newestColor = freshnessColor(newestAge);
  const oldestColor = freshnessColor(oldestAge);

  return (
    <Card title="ML Models">
      <div className={s.mlModelsGrid}>
        <div>
          <div className={s.mlStatLabel}>Models</div>
          <div className={s.mlStatValueLarge}>{count}</div>
        </div>
        <div>
          <div className={s.mlStatLabel}>Newest</div>
          <div className={s.mlStatValueMd} style={{ color: newestColor }}>
            {fmtAge(newestAge)}
          </div>
        </div>
        <div>
          <div className={s.mlStatLabel}>Oldest</div>
          <div className={s.mlStatValueMd} style={{ color: oldestColor }}>
            {fmtAge(oldestAge)}
          </div>
        </div>
      </div>
    </Card>
  );
}

// ── Backtest Results Table ──────────────────────────────────────────────────
function BacktestTable({ backtests }) {
  if (!backtests || backtests.length === 0) {
    return (
      <Card title="Backtest Results">
        <div className={s.backtestEmpty}>No backtest data available</div>
      </Card>
    );
  }

  const sorted = [...backtests].sort((a, b) => (b.age_hours ?? 0) - (a.age_hours ?? 0));

  return (
    <Card title="Backtest Results">
      <div className={s.backtestTableWrap}>
        <table className={s.backtestTable}>
          <thead>
            <tr>
              {['Region', 'Age', 'Size'].map(h => (
                <th key={h} className={s.backtestTh}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {sorted.map((bt, i) => {
              const color = backtestFreshnessColor(bt.age_hours);
              return (
                <tr key={bt.region || i} className={i % 2 === 0 ? s.backtestTr : s.backtestTrAlt}>
                  <td className={s.backtestTdRegion}>{bt.region || '--'}</td>
                  <td className={s.backtestTdAge}>
                    <span className={s.backtestAgePill} style={{ color, background: `${color}12` }}>
                      {fmtAge(bt.age_hours)}
                    </span>
                  </td>
                  <td className={s.backtestTdSize}>
                    {bt.size_mb != null ? `${bt.size_mb} MB` : '--'}
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </Card>
  );
}

// ═════════════════════════════════════════════════════════════════════════════
// Main Page Component
// ═════════════════════════════════════════════════════════════════════════════
export default function PipelineMonitorPage() {
  const [pipeline, setPipeline] = useState(null);
  const [error, setError] = useState(null);
  const [submitting, setSubmitting] = useState({});

  useEffect(() => {
    let mounted = true;
    const fetchData = () => {
      fetch(`${getApiBase()}/system/pipeline`)
        .then(r => {
          if (!r.ok) throw new Error(`HTTP ${r.status}`);
          return r.json();
        })
        .then(data => { if (mounted) { setPipeline(data); setError(null); } })
        .catch(err => { if (mounted) setError(err.message); });
    };
    fetchData();
    const iv = setInterval(fetchData, 5000);
    return () => { mounted = false; clearInterval(iv); };
  }, []);

  const submitJob = useCallback(async (key, body) => {
    setSubmitting(prev => ({ ...prev, [key]: true }));
    try {
      const resp = await fetch(`${getApiBase()}/remote/submit`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
      });
      if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
    } catch (err) {
      console.error(`Failed to submit ${key}:`, err);
    } finally {
      setSubmitting(prev => ({ ...prev, [key]: false }));
    }
  }, []);

  const PHASE_MAP = {
    ohlcv: 'OHLCV', signals: 'Signals', backtests: 'Backtests',
    feature_gen: 'Features', ml_train: 'ML Train', ml_refresh: 'ML Refresh',
    ec2_sync: 'EC2 Sync', done: 'Done',
  };

  const pipelineRun = pipeline?.pipeline;
  const currentPhase = pipelineRun ? (PHASE_MAP[pipelineRun.phase] || pipelineRun.phase) : null;
  const elapsedSec = pipelineRun?.elapsed_seconds ?? null;
  const features = pipeline?.features || {};
  const models = pipeline?.ml_models || {};
  const backtests = pipeline?.backtest_results || [];

  return (
    <div className={s.page}>
      {/* ── Header + Action Buttons ────────────────────────────────── */}
      <div className={s.header}>
        <div>
          <h1 className={s.headerTitle}>Pipeline Monitor</h1>
          <p className={s.headerSubtitle}>
            Real-time data pipeline status and freshness tracking
          </p>
        </div>
        <div className={s.headerActions}>
          <ActionButton
            label="Run Full Pipeline"
            loading={submitting.full}
            onClick={() => submitJob('full', { job_type: 'full_pipeline' })}
          />
          <ActionButton
            label="Run Backtests Only"
            loading={submitting.backtest}
            color={C.amber}
            onClick={() => submitJob('backtest', { job_type: 'backtest', params: { region: 'us' } })}
          />
          <ActionButton
            label="Refresh Features"
            loading={submitting.features}
            color={C.green}
            onClick={() => submitJob('features', { job_type: 'ml_train' })}
          />
        </div>
      </div>

      {/* ── Error banner ───────────────────────────────────────────── */}
      {error && (
        <div className={s.errorBanner}>
          Failed to fetch pipeline status: {error}
        </div>
      )}

      {/* ── Phase Stepper ──────────────────────────────────────────── */}
      <div className={s.stepperCard}>
        <div className={s.stepperHeader}>
          <span className={s.stepperLabel}>Pipeline Progress</span>
          <div className={s.stepperMeta}>
            {currentPhase && currentPhase !== 'Done' && (
              <span className={s.statusPillActive}>
                <span className={s.statusDot} />
                {pipelineRun?.detail || currentPhase}
              </span>
            )}
            {currentPhase === 'Done' && (
              <span className={s.statusPillDone}>Complete</span>
            )}
            {!currentPhase && (
              <span className={s.statusPillIdle}>Idle</span>
            )}
            <span className={s.elapsedText}>
              {elapsedSec != null ? `Elapsed: ${fmtElapsed(elapsedSec)}` :
               pipelineRun?.timestamp ? `Last: ${new Date(pipelineRun.timestamp).toLocaleString()}` : ''}
            </span>
          </div>
        </div>
        <PhaseStepper currentPhase={currentPhase} />
      </div>

      {/* ── Feature Freshness Cards ────────────────────────────────── */}
      <div className={s.featureRow}>
        <FeatureCard label="US Features" data={features.us} />
        <FeatureCard label="Crypto Features" data={features.crypto} />
      </div>

      {/* ── ML Models ──────────────────────────────────────────────── */}
      <div className={s.mlModelsSection}>
        <MLModelsCard models={models} />
      </div>

      {/* ── Backtest Results Table ──────────────────────────────────── */}
      <BacktestTable backtests={backtests} />

      {/* ── Loading state (no data yet, no error) ──────────────────── */}
      {!pipeline && !error && (
        <div className={s.loadingState}>Loading pipeline data...</div>
      )}
    </div>
  );
}
